#include <stdbool.h>
#include <stdint.h>

// Zigbee stack includes
#include "zcl.h"
#include "nwk.h"

// Define permitJoin mode for easy device addition during setup
#define PERMIT_JOIN 1

// Function to handle network commissioning with trust center link key
void networkCommissioning(void) {
    // Set the network commissioning flag
    nwk_setCommissioningFlag(true);

    // Enable permitJoin mode
    nwk_enablePermitJoin(PERMIT_JOIN);
}

// Function to join a Zigbee network using the trust center link key
void joinNetwork(void) {
    // Get the trust center link key from flash memory
    uint8_t trustCenterLinkKey[16];
    nwk_getTrustCenterLinkKey(trustCenterLinkKey);

    // Join the network with the trust center link key
    nwk_joinNetwork(trustCenterLinkKey);
}

// Main function to initialize and join the Zigbee network
void main(void) {
    // Initialize the Zigbee stack
    zcl_init();

    // Network commissioning with trust center link key
    networkCommissioning();

    // Join the Zigbee network
    joinNetwork();
}